import pandas as pd
import matplotlib.pyplot as plt
import os

# Load the data generated by your C++ code

df = pd.read_csv(csv_path)

print(df.columns)

plt.figure(figsize=(10, 6))

# Plot Histograms
plt.hist(df['Original'], bins=50, label='Original Payoffs (Vanilla MC)', color='red')
plt.hist(df['Adjusted'], bins=50, alpha=0.5, label='Adjusted Payoffs (Control Variate)', color='blue')

# Add Mean Lines
plt.axvline(df['Original'].mean(), color='green', linestyle='--', label=f'Original Mean: {df["Original"].mean():.2f}')
plt.axvline(df['Adjusted'].mean(), color='black', linestyle='--', label=f'Adjusted Mean: {df["Adjusted"].mean():.2f}')

plt.axvline(df['Original'].var(), color='green', linestyle='--', label=f'Original Variance: {df["Original"].var():.2f}')
plt.axvline(df['Adjusted'].var(), color='black', linestyle='--', label=f'Adjusted Variance: {df["Adjusted"].var():.2f}')


plt.title('Monte Carlo: Variance Reduction via Control Variates')
plt.xlabel('Payoff')
plt.ylabel('Frequency')
plt.legend()
plt.grid(axis='y', alpha=0.3)

plt.savefig('variance_reduction_plot.png')
plt.show()
